function fileToCompressedDataUrl(file,maxDimension=1600,quality=.82){return new Promise((resolve,reject)=>{if(!file||!file.type.startsWith("image/"))return reject(new Error("Please choose an image file."));const reader=new FileReader();reader.onerror=()=>reject(new Error("The photo could not be read."));reader.onload=()=>{const image=new Image();image.onerror=()=>reject(new Error("The photo could not be processed."));image.onload=()=>{const scale=Math.min(1,maxDimension/Math.max(image.width,image.height)),canvas=document.createElement("canvas");canvas.width=Math.max(1,Math.round(image.width*scale));canvas.height=Math.max(1,Math.round(image.height*scale));canvas.getContext("2d").drawImage(image,0,0,canvas.width,canvas.height);resolve(canvas.toDataURL("image/jpeg",quality))};image.src=reader.result};reader.readAsDataURL(file)})}
async function uploadPhotoToDrive(file,photoType,status){if(file.size>15*1024*1024)throw new Error("Please choose a photo smaller than 15 MB.");if(status)status.textContent="Preparing photo...";const dataUrl=await fileToCompressedDataUrl(file),callbackId=`upload-${Date.now()}-${Math.random().toString(36).slice(2)}`,frameName=`drive-${callbackId}`,iframe=document.createElement("iframe"),form=document.createElement("form");iframe.name=frameName;iframe.style.display="none";document.body.appendChild(iframe);form.method="POST";form.action=DRIVE_UPLOAD_WEB_APP_URL;form.target=frameName;form.style.display="none";const fields={callbackId,fileName:file.name||`${photoType}-${Date.now()}.jpg`,mimeType:"image/jpeg",photoType,base64:dataUrl.split(",")[1]};Object.entries(fields).forEach(([n,v])=>{const input=document.createElement("input");input.type="hidden";input.name=n;input.value=v;form.appendChild(input)});document.body.appendChild(form);return new Promise((resolve,reject)=>{const timer=setTimeout(()=>{cleanup();reject(new Error("Photo upload timed out."))},120000);const onMessage=event=>{const data=event.data||{};if(data.type!=="mcgriffs-drive-upload"||data.callbackId!==callbackId)return;clearTimeout(timer);cleanup();data.ok?resolve(data):reject(new Error(data.error||"Photo upload failed."))};function cleanup(){window.removeEventListener("message",onMessage);form.remove();iframe.remove()}window.addEventListener("message",onMessage);if(status)status.textContent="Uploading photo...";form.submit()})}
function photoControl(prefix,label,url=""){return `<div class="photo-control"><label>${label}</label><input id="${prefix}File" type="file" accept="image/*" capture="environment"><input id="${prefix}Url" type="hidden" value="${esc(url)}"><small id="${prefix}Status">${url?"Current photo saved.":"Choose or take a picture."}</small><img id="${prefix}Preview" src="${esc(imageUrl(url))}" style="${url?"":"display:none"}"></div>`}
function connectPhoto(prefix,type){const input=$(`${prefix}File`);if(!input)return;input.onchange=async()=>{const file=input.files?.[0];if(!file)return;const status=$(`${prefix}Status`),preview=$(`${prefix}Preview`);try{const result=await uploadPhotoToDrive(file,type,status);$(`${prefix}Url`).value=result.url;preview.src=imageUrl(result.url);preview.style.display="block";status.textContent="Photo uploaded.";toast("Photo uploaded")}catch(error){status.textContent=error.message;alert(error.message)}}}
function callEmailService(action,payload,status=null){const callbackId=`mail-${Date.now()}-${Math.random().toString(36).slice(2)}`,frameName=`mail-${callbackId}`,iframe=document.createElement("iframe"),form=document.createElement("form");iframe.name=frameName;iframe.style.display="none";document.body.appendChild(iframe);form.method="POST";form.action=EMAIL_SERVICE_WEB_APP_URL;form.target=frameName;form.style.display="none";Object.entries({action,callbackId,payload:JSON.stringify(payload)}).forEach(([n,v])=>{const input=document.createElement("input");input.type="hidden";input.name=n;input.value=v;form.appendChild(input)});document.body.appendChild(form);if(status)status.textContent="Sending...";return new Promise((resolve,reject)=>{const timer=setTimeout(()=>{cleanup();reject(new Error("Email service timed out."))},120000);const onMessage=event=>{const data=event.data||{};if(data.type!=="mcgriffs-email-service"||data.callbackId!==callbackId)return;clearTimeout(timer);cleanup();data.ok?resolve(data):reject(new Error(data.error||"Email failed."))};function cleanup(){window.removeEventListener("message",onMessage);form.remove();iframe.remove()}window.addEventListener("message",onMessage);form.submit()})}
function canvasHasInk(canvas){const data=canvas.getContext("2d").getImageData(0,0,canvas.width,canvas.height).data;for(let i=3;i<data.length;i+=4)if(data[i]>0)return true;return false}

const profiles={owner:{name:"Mike Roquet",email:"cody.dezwarte+owner@gmail.com",role:"owner"},manager:{name:"Cody DeZwarte",email:"cody.dezwarte@gmail.com",role:"manager"}};
const state={equipment:[],customers:[],rentals:[],reservations:[],maintenance:[],settings:{},profile:null,view:"dashboard",search:""};
let selectedProfile=null,listenersStarted=false;

function toast(message){$("toast").textContent=message;$("toast").classList.remove("hidden");clearTimeout(window.__toast);window.__toast=setTimeout(()=>$("toast").classList.add("hidden"),2300)}
function openModal(title,html){$("modalTitle").textContent=title;$("modalBody").innerHTML=html;$("modal").classList.remove("hidden")}
function closeModal(){$("modal").classList.add("hidden")}
function toDate(v){if(!v)return null;const d=v?.toDate?v.toDate():new Date(v);return isNaN(d)?null:d}
function fmt(v){const d=toDate(v);return d?d.toLocaleString():String(v||"")}
function dateInput(v){const d=toDate(v)||new Date();d.setMinutes(d.getMinutes()-d.getTimezoneOffset());return d.toISOString().slice(0,16)}
function money(v){return Number(v||0).toLocaleString("en-US",{style:"currency",currency:"USD"})}
function activeRental(id){return state.rentals.find(r=>r.equipmentId===id&&!r.actualReturnAt)}
function activeReservation(id){return state.reservations.filter(r=>r.equipmentId===id&&String(r.status||"Reserved").toLowerCase()==="reserved"&&(toDate(r.endAt||r.startAt)||new Date(0))>=new Date()).sort((a,b)=>(toDate(a.startAt)||0)-(toDate(b.startAt)||0))[0]}
function equipmentStatus(e){if(String(e.status||"").toLowerCase()==="maintenance"||e.inMaintenance)return"Maintenance";if(activeRental(e.id))return"Rented";if(activeReservation(e.id))return"Reserved";return"Available"}
function imageUrl(url){const text=String(url||"");const m=text.match(/[?&]id=([^&]+)/i)||text.match(/\/d\/([^/?#]+)/i);return m?`https://lh3.googleusercontent.com/d/${encodeURIComponent(m[1])}=w1200`:text}
function customerName(c){return c?.name||`${c?.firstName||""} ${c?.lastName||""}`.trim()||"Customer"}
function equipmentName(id){return state.equipment.find(e=>e.id===id)?.name||"Equipment"}
function parseLines(value){return String(value||"").split("\n").map(x=>x.trim()).filter(Boolean)}
function options(rows,labelFn,selected=""){return rows.map(r=>`<option value="${esc(r.id)}" ${r.id===selected?"selected":""}>${esc(labelFn(r))}</option>`).join("")}

function setView(view){state.view=view;document.querySelectorAll(".view").forEach(v=>v.classList.add("hidden"));$(`${view}View`)?.classList.remove("hidden");document.querySelectorAll(".nav").forEach(b=>b.classList.toggle("active",b.dataset.view===view));const labels={dashboard:["Dashboard","Today at a glance"],equipment:["Equipment","Inventory, rates, and customer resources"],customers:["Customers","Customer records and rental history"],rentals:["Rentals","Checkout, active rentals, and returns"],reservations:["Reservations","Upcoming bookings and pickups"],maintenance:["Maintenance","Service and repair records"]};$("pageTitle").textContent=labels[view]?.[0]||view;$("pageSubtitle").textContent=labels[view]?.[1]||""}
function render(){renderDashboard();renderEquipment();renderCustomers();renderRentals();renderReservations();renderMaintenance()}

function renderDashboard(){const statuses=state.equipment.map(e=>equipmentStatus(e));$("kpiEquipment").textContent=state.equipment.length;$("kpiAvailable").textContent=statuses.filter(x=>x==="Available").length;$("kpiRented").textContent=statuses.filter(x=>x==="Rented").length;$("kpiReserved").textContent=statuses.filter(x=>x==="Reserved").length;$("kpiMaintenance").textContent=statuses.filter(x=>x==="Maintenance").length;
 const active=state.rentals.filter(r=>!r.actualReturnAt).sort((a,b)=>(toDate(a.dueAt||a.endAt)||0)-(toDate(b.dueAt||b.endAt)||0)).slice(0,8);$("activeRentals").innerHTML=active.length?active.map(r=>`<div class="list-row"><div><strong>${esc(r.equipmentName||equipmentName(r.equipmentId))}</strong><br><small>${esc(r.customerName||"Customer")}</small></div><div><small>Due</small><br><strong>${esc(fmt(r.dueAt||r.endAt||r.expectedReturnAt))}</strong></div></div>`).join(""):`<div class="empty">No equipment is currently out.</div>`;
 const upcoming=state.reservations.filter(r=>String(r.status||"Reserved")==="Reserved"&&(toDate(r.endAt||r.startAt)||new Date(0))>=new Date()).sort((a,b)=>(toDate(a.startAt)||0)-(toDate(b.startAt)||0)).slice(0,8);$("upcomingReservations").innerHTML=upcoming.length?upcoming.map(r=>`<div class="list-row"><div><strong>${esc(r.equipmentName||equipmentName(r.equipmentId))}</strong><br><small>${esc(r.customerName||"Customer")}</small></div><strong>${esc(fmt(r.startAt))}</strong></div>`).join(""):`<div class="empty">No upcoming reservations.</div>`}

function renderEquipment(){const q=($("equipmentSearch")?.value||state.search||"").toLowerCase(),filter=$("statusFilter")?.value||"";const rows=state.equipment.filter(e=>`${e.name||""} ${e.category||""} ${e.brand||""} ${e.model||""} ${e.serialNumber||""}`.toLowerCase().includes(q)&&(!filter||equipmentStatus(e)===filter));$("equipmentGrid").innerHTML=rows.length?rows.map(e=>{const status=equipmentStatus(e),r=activeRental(e.id);return `<article class="equipment-card"><div class="equipment-photo">${e.photoUrl||e.imageUrl?`<img src="${esc(imageUrl(e.photoUrl||e.imageUrl))}" alt="${esc(e.name)}">`:`<div class="muted">No photo</div>`}</div><div class="equipment-body"><span class="badge ${status}">${status}</span><h3>${esc(e.name||"Unnamed equipment")}</h3><p class="muted">${esc(e.category||"")}</p><div class="rate-line">${e.dailyRate?`<span>Day ${money(e.dailyRate)}</span>`:""}${e.weeklyRate?`<span>Week ${money(e.weeklyRate)}</span>`:""}${e.deposit?`<span>Deposit ${money(e.deposit)}</span>`:""}</div>${r?`<div class="quick-note"><strong>Out to:</strong> ${esc(r.customerName||"Customer")} · Due ${esc(fmt(r.dueAt||r.endAt))}</div>`:""}<div class="card-actions">${status==="Available"?`<button class="primary-action" data-rent-equipment="${e.id}">Rent</button><button class="warning-action" data-reserve-equipment="${e.id}">Reserve</button>`:""}${status==="Rented"?`<button class="warning-action" data-return-rental="${r?.id||""}">Return</button>`:""}<button data-edit-equipment="${e.id}">Edit</button><button class="secondary" data-service-equipment="${e.id}">Service</button><button class="secondary" data-qr-equipment="${e.id}">QR</button></div></div></article>`}).join(""):`<div class="empty">No equipment found.</div>`;
 document.querySelectorAll("[data-edit-equipment]").forEach(b=>b.onclick=()=>equipmentForm(state.equipment.find(e=>e.id===b.dataset.editEquipment)));document.querySelectorAll("[data-rent-equipment]").forEach(b=>b.onclick=()=>rentalForm(null,b.dataset.rentEquipment));document.querySelectorAll("[data-reserve-equipment]").forEach(b=>b.onclick=()=>reservationForm(null,b.dataset.reserveEquipment));document.querySelectorAll("[data-return-rental]").forEach(b=>b.onclick=()=>returnForm(state.rentals.find(r=>r.id===b.dataset.returnRental)));document.querySelectorAll("[data-service-equipment]").forEach(b=>b.onclick=()=>maintenanceForm(null,b.dataset.serviceEquipment));document.querySelectorAll("[data-qr-equipment]").forEach(b=>b.onclick=()=>showQr(state.equipment.find(e=>e.id===b.dataset.qrEquipment)))}

function renderCustomers(){const rows=[...state.customers].sort((a,b)=>customerName(a).localeCompare(customerName(b)));$("customersTable").innerHTML=rows.length?`<table><thead><tr><th>Name</th><th>Phone</th><th>Email</th><th>City</th><th>Rentals</th><th></th></tr></thead><tbody>${rows.map(c=>`<tr><td><strong>${esc(customerName(c))}</strong></td><td>${esc(c.phone||"")}</td><td>${esc(c.email||"")}</td><td>${esc(c.city||"")}</td><td>${state.rentals.filter(r=>r.customerId===c.id).length}</td><td><div class="action-cell"><button class="secondary" data-edit-customer="${c.id}">Edit</button><button data-rent-customer="${c.id}">New Rental</button></div></td></tr>`).join("")}</tbody></table>`:`<div class="empty">No customers found.</div>`;document.querySelectorAll("[data-edit-customer]").forEach(b=>b.onclick=()=>customerForm(state.customers.find(c=>c.id===b.dataset.editCustomer)));document.querySelectorAll("[data-rent-customer]").forEach(b=>b.onclick=()=>rentalForm(null,"",b.dataset.rentCustomer))}

function renderRentals(){const q=($('rentalSearch')?.value||'').toLowerCase(),filter=$('rentalFilter')?.value||'';const now=new Date();const rows=[...state.rentals].filter(r=>{const due=toDate(r.dueAt||r.endAt),overdue=!r.actualReturnAt&&due&&due<now;const hay=`${r.customerName||''} ${r.equipmentName||''} ${r.rentalNumber||''}`.toLowerCase();return(!q||hay.includes(q))&&(!filter||(filter==='out'&&!r.actualReturnAt)||(filter==='overdue'&&overdue)||(filter==='returned'&&r.actualReturnAt))}).sort((a,b)=>(toDate(b.startAt)||0)-(toDate(a.startAt)||0));$('rentalsTable').innerHTML=rows.length?`<table><thead><tr><th>Customer</th><th>Equipment</th><th>Start</th><th>Due</th><th>Amount</th><th>Contract</th><th>Status</th><th></th></tr></thead><tbody>${rows.map(r=>{const due=toDate(r.dueAt||r.endAt),overdue=!r.actualReturnAt&&due&&due<now,status=r.actualReturnAt?'Returned':overdue?'Overdue':'Out';return`<tr><td><strong>${esc(r.customerName||'')}</strong></td><td>${esc(r.equipmentName||equipmentName(r.equipmentId))}</td><td>${esc(fmt(r.startAt))}</td><td>${esc(fmt(r.dueAt||r.endAt))}</td><td>${money(r.rentalAmount)}</td><td><span class="badge ${r.customerSignature?'completed':'scheduled'}">${r.customerSignature?'Signed':'Unsigned'}</span></td><td><span class="badge ${status.toLowerCase()}">${status}</span></td><td><div class="action-cell"><button class="secondary" data-contract-rental="${r.id}">Contract</button><button class="secondary" data-edit-rental="${r.id}">Edit</button>${!r.actualReturnAt?`<button data-return-rental="${r.id}">Return</button>`:''}</div></td></tr>`}).join('')}</tbody></table>`:`<div class="empty">No rentals found.</div>`;document.querySelectorAll('[data-edit-rental]').forEach(b=>b.onclick=()=>rentalForm(state.rentals.find(r=>r.id===b.dataset.editRental)));document.querySelectorAll('[data-return-rental]').forEach(b=>b.onclick=()=>returnForm(state.rentals.find(r=>r.id===b.dataset.returnRental)));document.querySelectorAll('[data-contract-rental]').forEach(b=>b.onclick=()=>showContract(state.rentals.find(r=>r.id===b.dataset.contractRental)))}

function renderReservations(){const rows=[...state.reservations].sort((a,b)=>(toDate(a.startAt)||0)-(toDate(b.startAt)||0));$("reservationsTable").innerHTML=rows.length?`<table><thead><tr><th>Customer</th><th>Equipment</th><th>Starts</th><th>Ends</th><th>Status</th><th></th></tr></thead><tbody>${rows.map(r=>`<tr><td><strong>${esc(r.customerName||"")}</strong></td><td>${esc(r.equipmentName||equipmentName(r.equipmentId))}</td><td>${esc(fmt(r.startAt))}</td><td>${esc(fmt(r.endAt))}</td><td><span class="badge ${String(r.status||"Reserved").toLowerCase()}">${esc(r.status||"Reserved")}</span></td><td><div class="action-cell">${String(r.status||"Reserved")==="Reserved"?`<button data-start-reservation="${r.id}">Start Rental</button><button class="secondary" data-edit-reservation="${r.id}">Edit</button><button class="danger" data-cancel-reservation="${r.id}">Cancel</button>`:""}</div></td></tr>`).join("")}</tbody></table>`:`<div class="empty">No reservations found.</div>`;document.querySelectorAll("[data-edit-reservation]").forEach(b=>b.onclick=()=>reservationForm(state.reservations.find(r=>r.id===b.dataset.editReservation)));document.querySelectorAll("[data-cancel-reservation]").forEach(b=>b.onclick=async()=>{if(confirm("Cancel this reservation?")){await updateDoc(doc(db,"reservations",b.dataset.cancelReservation),{status:"Cancelled",updatedAt:serverTimestamp()});toast("Reservation cancelled")}});document.querySelectorAll("[data-start-reservation]").forEach(b=>b.onclick=()=>{const r=state.reservations.find(x=>x.id===b.dataset.startReservation);rentalForm(null,r.equipmentId,r.customerId,r)})}

function renderMaintenance(){const rows=[...state.maintenance].sort((a,b)=>(toDate(b.date||b.createdAt)||0)-(toDate(a.date||a.createdAt)||0));$("maintenanceTable").innerHTML=rows.length?`<table><thead><tr><th>Equipment</th><th>Service</th><th>Date</th><th>Status</th><th>Cost</th><th>Next Due</th><th></th></tr></thead><tbody>${rows.map(m=>`<tr><td><strong>${esc(m.equipmentName||equipmentName(m.equipmentId))}</strong></td><td>${esc(m.description||m.type||m.serviceType||"")}</td><td>${esc(fmt(m.date||m.createdAt))}</td><td><span class="badge ${String(m.status||"Completed").toLowerCase()}">${esc(m.status||"Completed")}</span></td><td>${money(m.cost)}</td><td>${esc(fmt(m.nextServiceDate))}</td><td><button class="secondary" data-edit-maintenance="${m.id}">Edit</button></td></tr>`).join("")}</tbody></table>`:`<div class="empty">No maintenance records found.</div>`;document.querySelectorAll("[data-edit-maintenance]").forEach(b=>b.onclick=()=>maintenanceForm(state.maintenance.find(m=>m.id===b.dataset.editMaintenance)))}

